insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 10, 'In a Venn diagram, Students is fully inside Readers, and Singers partly overlaps Readers. Which statement is definitely true?', 'Venn diagram में Students, Readers के अंदर है और Singers, Readers को partly overlap करता है। Definitely true statement कौन-सा है?', 'Students lies completely within Readers, so every Students is Readers. Therefore, answer = All Students are Readers.', 'A Venn diagram only gives guaranteed relations shown by full containment, separation, or overlap. Do not infer more than the diagram states. Final answer is All Students are Readers.', 'Students पूरी तरह Readers के अंदर है, इसलिए every Students, Readers है। अतः answer = All Students are Readers।', 'Venn diagram सिर्फ वही guaranteed relation देता है जो full containment, separation या overlap से दिखता है। Extra inference न करें। Final answer All Students are Readers है।', 'MEDIUM', array['reasoning','venn-diagram']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'All Singers are Readers', 'All Singers are Readers', false, 'Converted a partial overlap between Singers and Readers into full inclusion.', 'Singers और Readers के partial overlap को full inclusion मान लिया।');
